import java.util.*;

class Solution {
    // Function to replace elements with their rank
    public List<Integer> replaceWithRank(int[] arr) {
        List<Integer> rankList = new ArrayList<>();

        // Loop through each element
        for (int i = 0; i < arr.length; i++) {
            // Set to store unique elements smaller than current
            Set<Integer> smaller = new HashSet<>();

            // Compare with all elements
            for (int j = 0; j < arr.length; j++) {
                if (arr[j] < arr[i]) {
                    smaller.add(arr[j]);
                }
            }

            // Rank = count of unique smaller elements + 1
            int rank = smaller.size() + 1;
            rankList.add(rank);
        }

        return rankList;
    }
}

