class Solution {
    // Function to replace elements by their rank in the array
    replaceWithRank(arr) {
        // Make a sorted copy of the array
        let sortedArr = [...arr].sort((a, b) => a - b);

        // Create a map to store rank of each unique number
        let rankMap = new Map();
        let rank = 1;

        // Assign ranks to unique elements
        for (let num of sortedArr) {
            if (!rankMap.has(num)) {
                rankMap.set(num, rank);
                rank++;
            }
        }

        // Replace original array values with ranks
        let result = arr.map(num => rankMap.get(num));
        return result;
    }
}

